import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.Pywvta2k.js";const f=JSON.parse('{"title":"金匮要略","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/01-先秦两汉/03-金匮要略.md","filePath":"tcm-data/01-先秦两汉/03-金匮要略.md","lastUpdated":1781084559000}'),r={name:"tcm-data/01-先秦两汉/03-金匮要略.md"};function n(s,t,o,i,g,h){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="金匮要略" tabindex="-1">金匮要略 <a class="header-anchor" href="#金匮要略" aria-label="Permalink to &quot;金匮要略&quot;">​</a></h1><blockquote><p>张仲景著，原为《伤寒杂病论》的&quot;杂病&quot;部分 中医第一部内伤杂病专著</p></blockquote><hr><h2 id="一、基本信息" tabindex="-1">一、基本信息 <a class="header-anchor" href="#一、基本信息" aria-label="Permalink to &quot;一、基本信息&quot;">​</a></h2><ul><li><strong>原属</strong>：《伤寒杂病论》的杂病部分</li><li><strong>发现</strong>：北宋翰林学士王洙在馆阁残书中发现</li><li><strong>编校</strong>：林亿等校正，分为3卷25篇</li><li><strong>篇量</strong>：25篇，载方262首</li><li><strong>学术地位</strong>：中医四大经典之一，<strong>&quot;方书之祖，杂病之宗&quot;</strong></li></ul><hr><h2 id="二、核心理论" tabindex="-1">二、核心理论 <a class="header-anchor" href="#二、核心理论" aria-label="Permalink to &quot;二、核心理论&quot;">​</a></h2><h3 id="_1-脏腑经络辨证-——-内伤杂病的辨证体系" tabindex="-1">1. 脏腑经络辨证 —— 内伤杂病的辨证体系 <a class="header-anchor" href="#_1-脏腑经络辨证-——-内伤杂病的辨证体系" aria-label="Permalink to &quot;1. 脏腑经络辨证 —— 内伤杂病的辨证体系&quot;">​</a></h3><p>与《伤寒论》按六经分类不同，《金匮要略》<strong>以脏腑经络为纲</strong>，按疾病分类：</p><table tabindex="0"><thead><tr><th style="text-align:left;">篇次</th><th style="text-align:left;">病证分类</th></tr></thead><tbody><tr><td style="text-align:left;">第1篇</td><td style="text-align:left;"><strong>脏腑经络先后病</strong>（总论）</td></tr><tr><td style="text-align:left;">第2-6篇</td><td style="text-align:left;">经络病：痉湿暍、百合狐惑、疟病、中风历节、血痹虚劳</td></tr><tr><td style="text-align:left;">第7-11篇</td><td style="text-align:left;">脏腑病：肺痿肺痈、奔豚气、胸痹心痛、腹满寒疝、五脏风寒</td></tr><tr><td style="text-align:left;">第12-14篇</td><td style="text-align:left;">水气病：痰饮咳嗽、消渴小便不利、水气病</td></tr><tr><td style="text-align:left;">第15-19篇</td><td style="text-align:left;">黄疸、惊悸吐衄、呕吐哕下利、疮痈肠痈、趺蹶手指肿</td></tr><tr><td style="text-align:left;">第20-22篇</td><td style="text-align:left;">妇人病：妊娠、产后、杂病</td></tr><tr><td style="text-align:left;">第23-25篇</td><td style="text-align:left;">杂疗方、食物禁忌</td></tr></tbody></table><h3 id="_2-治未病-——-脏腑相传" tabindex="-1">2. 治未病 —— 脏腑相传 <a class="header-anchor" href="#_2-治未病-——-脏腑相传" aria-label="Permalink to &quot;2. 治未病 —— 脏腑相传&quot;">​</a></h3><blockquote><p><strong>「夫治未病者，见肝之病，知肝传脾，当先实脾。」</strong>（第1篇）</p></blockquote><p><strong>这一条是黄元御&quot;土湿木郁&quot;理论的直接源头。</strong> 仲景指出肝病最易传脾，所以治疗肝病必须先健脾胃——这正是该男性患者的&quot;水寒土湿木郁&quot;病机的经典依据。</p><h3 id="_3-虚实异治" tabindex="-1">3. 虚实异治 <a class="header-anchor" href="#_3-虚实异治" aria-label="Permalink to &quot;3. 虚实异治&quot;">​</a></h3><blockquote><p><strong>「虚虚实实，补不足，损有余。」</strong></p></blockquote><h3 id="_4-整体观" tabindex="-1">4. 整体观 <a class="header-anchor" href="#_4-整体观" aria-label="Permalink to &quot;4. 整体观&quot;">​</a></h3><blockquote><p><strong>「五脏元真通畅，人即安和。」</strong></p></blockquote><hr><h2 id="三、代表方剂" tabindex="-1">三、代表方剂 <a class="header-anchor" href="#三、代表方剂" aria-label="Permalink to &quot;三、代表方剂&quot;">​</a></h2><h3 id="虚劳篇-不同类型患者常用" tabindex="-1">虚劳篇（不同类型患者常用） <a class="header-anchor" href="#虚劳篇-不同类型患者常用" aria-label="Permalink to &quot;虚劳篇（不同类型患者常用）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th><th style="text-align:left;">现代应用</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>小建中汤</strong></td><td style="text-align:left;">桂枝、芍药、甘草、生姜、大枣、饴糖</td><td style="text-align:left;">虚劳里急，悸衄，腹中痛，梦失精</td><td style="text-align:left;">虚劳、胃痛、贫血</td></tr><tr><td style="text-align:left;"><strong>黄芪建中汤</strong></td><td style="text-align:left;">小建中汤+黄芪</td><td style="text-align:left;">虚劳里急，诸不足</td><td style="text-align:left;">气虚体弱、胃溃疡</td></tr><tr><td style="text-align:left;"><strong>八味肾气丸</strong></td><td style="text-align:left;">地黄、山药、山萸、泽泻、丹皮、茯苓、桂枝、附子</td><td style="text-align:left;">虚劳腰痛，少腹拘急，小便不利</td><td style="text-align:left;">肾虚诸证</td></tr><tr><td style="text-align:left;"><strong>酸枣仁汤</strong></td><td style="text-align:left;">酸枣仁、甘草、知母、茯苓、川芎</td><td style="text-align:left;">虚烦不得眠</td><td style="text-align:left;">失眠、焦虑</td></tr><tr><td style="text-align:left;"><strong>炙甘草汤</strong></td><td style="text-align:left;">炙甘草、人参、生地、阿胶、麦冬、麻仁、桂枝、姜枣</td><td style="text-align:left;">虚劳不足，脉结悸</td><td style="text-align:left;">心律失常</td></tr></tbody></table><h3 id="胸痹心痛篇" tabindex="-1">胸痹心痛篇 <a class="header-anchor" href="#胸痹心痛篇" aria-label="Permalink to &quot;胸痹心痛篇&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>瓜蒌薤白白酒汤</strong></td><td style="text-align:left;">瓜蒌、薤白、白酒</td><td style="text-align:left;">胸痹，胸背痛</td></tr><tr><td style="text-align:left;"><strong>枳实薤白桂枝汤</strong></td><td style="text-align:left;">枳实、薤白、桂枝、厚朴、瓜蒌</td><td style="text-align:left;">胸痹，心中痞气</td></tr><tr><td style="text-align:left;"><strong>人参汤</strong></td><td style="text-align:left;">人参、干姜、白术、甘草（即理中丸）</td><td style="text-align:left;">胸痹属虚寒者</td></tr></tbody></table><h3 id="痰饮咳嗽篇-与水湿相关" tabindex="-1">痰饮咳嗽篇（与水湿相关） <a class="header-anchor" href="#痰饮咳嗽篇-与水湿相关" aria-label="Permalink to &quot;痰饮咳嗽篇（与水湿相关）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>苓桂术甘汤</strong></td><td style="text-align:left;">茯苓、桂枝、白术、甘草</td><td style="text-align:left;">心下痰饮，胸胁支满</td></tr><tr><td style="text-align:left;"><strong>己椒苈黄丸</strong></td><td style="text-align:left;">防己、椒目、葶苈、大黄</td><td style="text-align:left;">肠间水气</td></tr><tr><td style="text-align:left;"><strong>小半夏汤</strong></td><td style="text-align:left;">半夏、生姜</td><td style="text-align:left;">呕吐，痰饮</td></tr><tr><td style="text-align:left;"><strong>泽泻汤</strong></td><td style="text-align:left;">泽泻、白术</td><td style="text-align:left;">心下支饮，苦冒眩</td></tr></tbody></table><h3 id="水气病篇" tabindex="-1">水气病篇 <a class="header-anchor" href="#水气病篇" aria-label="Permalink to &quot;水气病篇&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>越婢汤</strong></td><td style="text-align:left;">麻黄、石膏、生姜、甘草、大枣</td><td style="text-align:left;">风水恶风，一身悉肿</td></tr><tr><td style="text-align:left;"><strong>防己黄芪汤</strong></td><td style="text-align:left;">防己、黄芪、白术、甘草、姜枣</td><td style="text-align:left;">风水，脉浮身重</td></tr><tr><td style="text-align:left;"><strong>真武汤</strong></td><td style="text-align:left;">附子、茯苓、白术、白芍、生姜</td><td style="text-align:left;">阳虚水泛</td></tr></tbody></table><h3 id="妇人病-相关" tabindex="-1">妇人病（相关） <a class="header-anchor" href="#妇人病-相关" aria-label="Permalink to &quot;妇人病（相关）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>温经汤</strong></td><td style="text-align:left;">吴萸、当归、川芎、芍药、人参、桂枝、阿胶、丹皮、生姜、甘草、半夏、麦冬</td><td style="text-align:left;">妇人少腹寒，久不受胎，崩漏</td></tr><tr><td style="text-align:left;"><strong>胶艾汤</strong></td><td style="text-align:left;">川芎、阿胶、甘草、艾叶、当归、芍药、生地</td><td style="text-align:left;">妇人有漏下</td></tr><tr><td style="text-align:left;"><strong>当归芍药散</strong></td><td style="text-align:left;">当归、芍药、川芎、茯苓、白术、泽泻</td><td style="text-align:left;">妇人腹中诸疾痛</td></tr><tr><td style="text-align:left;"><strong>桂枝茯苓丸</strong></td><td style="text-align:left;">桂枝、茯苓、丹皮、桃仁、芍药</td><td style="text-align:left;">癥瘕积聚，瘀血</td></tr></tbody></table><h3 id="其他经典方" tabindex="-1">其他经典方 <a class="header-anchor" href="#其他经典方" aria-label="Permalink to &quot;其他经典方&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方名</th><th style="text-align:left;">组成</th><th style="text-align:left;">主治</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>大黄牡丹汤</strong></td><td style="text-align:left;">大黄、丹皮、桃仁、芒硝、冬瓜仁</td><td style="text-align:left;">肠痈（阑尾炎）</td></tr><tr><td style="text-align:left;"><strong>薏苡附子败酱散</strong></td><td style="text-align:left;">薏苡仁、附子、败酱草</td><td style="text-align:left;">肠痈脓成</td></tr><tr><td style="text-align:left;"><strong>百合地黄汤</strong></td><td style="text-align:left;">百合、生地</td><td style="text-align:left;">百合病，意欲食复不能食</td></tr><tr><td style="text-align:left;"><strong>甘草小麦大枣汤</strong></td><td style="text-align:left;">甘草、小麦、大枣</td><td style="text-align:left;">妇人脏躁，悲伤欲哭</td></tr></tbody></table><hr><h2 id="四、经典名言精选" tabindex="-1">四、经典名言精选 <a class="header-anchor" href="#四、经典名言精选" aria-label="Permalink to &quot;四、经典名言精选&quot;">​</a></h2><blockquote><p><strong>「上工治未病，何也？师曰：夫治未病者，见肝之病，知肝传脾，当先实脾。」</strong></p></blockquote><blockquote><p><strong>「五脏元真通畅，人即安和。」</strong></p></blockquote><blockquote><p><strong>「若五脏元真通畅，人即安和；客气邪风，中人多死。」</strong></p></blockquote><blockquote><p><strong>「夫人禀五常，因风气而生长，风气虽能生万物，亦能害万物。」</strong></p></blockquote><blockquote><p><strong>「千般疢难，不越三条：一者，经络受邪入脏腑；二者，四肢九窍血脉相传；三者，房室金刃虫兽所伤。」</strong></p></blockquote><blockquote><p><strong>「夫诸病在脏，欲攻之，当随其所得而攻之。」</strong></p></blockquote><blockquote><p><strong>「病痰饮者，当以温药和之。」</strong></p></blockquote><blockquote><p><strong>「诸有水者，腰以下肿，当利小便；腰以上肿，当发汗乃愈。」</strong></p></blockquote><blockquote><p><strong>「夫肝之病，补用酸，助用焦苦，益用甘味之药调之。」</strong></p></blockquote><hr><h2 id="五、对后世的影响" tabindex="-1">五、对后世的影响 <a class="header-anchor" href="#五、对后世的影响" aria-label="Permalink to &quot;五、对后世的影响&quot;">​</a></h2><h3 id="黄元御" tabindex="-1">黄元御 <a class="header-anchor" href="#黄元御" aria-label="Permalink to &quot;黄元御&quot;">​</a></h3><ul><li>继承&quot;见肝之病，知肝传脾&quot; → 发展为&quot;水寒土湿木郁&quot;的核心病机模型</li><li>《金匮悬解》为黄元御注解《金匮要略》的专著</li></ul><h3 id="温病学派" tabindex="-1">温病学派 <a class="header-anchor" href="#温病学派" aria-label="Permalink to &quot;温病学派&quot;">​</a></h3><ul><li>《金匮》中对温病的论述（百合狐惑、阴阳毒等）为后世温病学奠定了基础</li></ul><h3 id="现代应用" tabindex="-1">现代应用 <a class="header-anchor" href="#现代应用" aria-label="Permalink to &quot;现代应用&quot;">​</a></h3><ul><li>经方在各科广泛使用</li><li>妇人三篇是中医妇科的核心文献</li><li>虚劳篇指导慢病调养</li></ul><hr><h2 id="六、《伤寒》与《金匮》的关系" tabindex="-1">六、《伤寒》与《金匮》的关系 <a class="header-anchor" href="#六、《伤寒》与《金匮》的关系" aria-label="Permalink to &quot;六、《伤寒》与《金匮》的关系&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">维度</th><th style="text-align:left;">伤寒论</th><th style="text-align:left;">金匮要略</th></tr></thead><tbody><tr><td style="text-align:left;">内容</td><td style="text-align:left;">外感病（伤寒）</td><td style="text-align:left;">内伤杂病</td></tr><tr><td style="text-align:left;">辨证</td><td style="text-align:left;">六经辨证</td><td style="text-align:left;">脏腑经络辨证</td></tr><tr><td style="text-align:left;">方数</td><td style="text-align:left;">113方</td><td style="text-align:left;">262方</td></tr><tr><td style="text-align:left;">侧重点</td><td style="text-align:left;">祛邪为主</td><td style="text-align:left;">扶正祛邪并重</td></tr><tr><td style="text-align:left;">两者合计</td><td style="text-align:left;">397法，375方（去重后）——中医临证的方剂宝库</td><td style="text-align:left;"></td></tr></tbody></table><hr><p><em>本条目为精简框架版。各篇病证可独立扩展为专题，妇人三篇尤值得单独展开。</em></p>',55)])])}const y=e(r,[["render",n]]);export{f as __pageData,y as default};
